const exp = $input.first().json;
const prospecto = exp.prospecto;

// Construir resumen del expediente para el Superior
const docs = [
  { nombre: 'INE Ambos Lados', estado: exp.ineAmbosLados },
  { nombre: 'Comprobante Domicilio', estado: exp.comprobanteDomicilio },
  { nombre: 'Resolución Pensión', estado: exp.resolucionPension },
  { nombre: 'Estados de Cuenta', estado: exp.estadosCuenta },
  { nombre: 'Foto con INE', estado: exp.fotoConIne }
];

const resumenDocs = docs.map(d => `${d.estado === 'APROBADO' ? '✅' : '❌'} ${d.nombre}`).join('\n');

return [{ json: {
  resumen: resumenDocs,
  nombre: prospecto.nombreCompleto,
  curp: prospecto.curp,
  monto: exp.montoPensionActual,
  banco: exp.institucionBancaria,
  clabe: exp.cuentaClabe,
  url_drive: exp.urlCarpetaDrive,
  expediente_id: exp.id,
  todos_aprobados: docs.every(d => d.estado === 'APROBADO')
} }];

